import{_ as t,o as i,c as a,ag as o}from"./chunks/framework.C9sp7nFj.js";const n="/screenshots/expense-claims.jpeg",m=JSON.parse('{"title":"File an expense claim","description":"","frontmatter":{},"headers":[],"relativePath":"guide/expense.md","filePath":"guide/expense.md","lastUpdated":1776630283000}'),s={name:"guide/expense.md"};function l(r,e,p,d,h,u){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="file-an-expense-claim" tabindex="-1">File an expense claim <a class="header-anchor" href="#file-an-expense-claim" aria-label="Permalink to &quot;File an expense claim&quot;">​</a></h1><p>Capture a receipt, enter an amount, submit.</p><h2 id="open-the-expense-hub" tabindex="-1">Open the Expense hub <a class="header-anchor" href="#open-the-expense-hub" aria-label="Permalink to &quot;Open the Expense hub&quot;">​</a></h2><p>Tap the <strong>Expense</strong> tab at the bottom of the screen.</p><figure class="screenshot"><img src="'+n+'" alt="Expense hub with totals and recent claims"><figcaption>Expense hub — Total Claimed, Pending, Approved, Paid at a glance, plus your recent submissions with status chips.</figcaption></figure><p>The hub shows:</p><ol><li><strong>Total Claimed</strong> and <strong>Pending</strong> — your all-time totals</li><li><strong>Approved</strong> and <strong>Paid</strong> — smaller tiles for amounts already processed</li><li><strong>&quot;New Claim&quot;</strong> — big button to start a new submission</li><li><strong>Recent Claims</strong> — your past submissions with status badges</li></ol><h2 id="making-a-new-claim" tabindex="-1">Making a new claim <a class="header-anchor" href="#making-a-new-claim" aria-label="Permalink to &quot;Making a new claim&quot;">​</a></h2><ol><li>Tap <strong>New Claim</strong>.</li><li>A claim line is shown. Each line is one receipt.</li><li>Fill in: <ul><li><strong>Type</strong> — pick from the dropdown (Travel, Meals, Supplies, …). The list comes from HR&#39;s configured Expense Claim Types.</li><li><strong>Date</strong> — the receipt date.</li><li><strong>Amount</strong> — the amount from the receipt.</li><li><strong>Description</strong> — a one-liner (e.g. &quot;Taxi from airport&quot;).</li><li><strong>Receipt</strong> — tap the photo slot, take a clear photo of the receipt.</li></ul></li><li>Add more lines with <strong>+ Add another line</strong> if your claim has multiple receipts.</li><li>The <strong>Total</strong> at the bottom sums all lines.</li><li>Tap <strong>Submit</strong>.</li></ol><h2 id="receipt-photo-—-required" tabindex="-1">Receipt photo — required <a class="header-anchor" href="#receipt-photo-—-required" aria-label="Permalink to &quot;Receipt photo — required&quot;">​</a></h2><p><strong>Every line needs a receipt photo.</strong> If you try to submit without one, you&#39;ll see:</p><blockquote><p><em>Every line needs a receipt photo.</em></p></blockquote><p>Tap the photo slot on any line missing a receipt, and either:</p><ul><li>Take a new photo with the camera</li><li>Pick from gallery (if your company allows it)</li></ul><p>The photo is saved locally first, uploaded to the server when you submit (or on next sync if offline).</p><h2 id="after-submit" tabindex="-1">After submit <a class="header-anchor" href="#after-submit" aria-label="Permalink to &quot;After submit&quot;">​</a></h2><p>You&#39;ll see either:</p><ul><li><strong>&quot;Submitted.&quot;</strong> — claim created, you can see it in Recent Claims</li><li><strong>&quot;Queued — will submit when online.&quot;</strong> — saved locally, syncs when network returns</li></ul><h2 id="viewing-your-claims" tabindex="-1">Viewing your claims <a class="header-anchor" href="#viewing-your-claims" aria-label="Permalink to &quot;Viewing your claims&quot;">​</a></h2><p>Your claims appear in the <strong>Recent Claims</strong> list at the bottom of the Expense hub.</p><p>Each row shows:</p><ul><li><strong>Claim reference</strong> (e.g. <code>HR-EXP-2026-00001</code>)</li><li><strong>Posting date</strong></li><li><strong>Total claimed amount</strong></li><li><strong>Status badge</strong> — Draft / Pending / Approved / Rejected / Paid</li></ul><h2 id="viewing-a-claim-in-detail" tabindex="-1">Viewing a claim in detail <a class="header-anchor" href="#viewing-a-claim-in-detail" aria-label="Permalink to &quot;Viewing a claim in detail&quot;">​</a></h2><p>Tap any claim row. A bottom sheet slides up with:</p><ul><li><strong>Date</strong> — when it was posted</li><li><strong>Status</strong></li><li><strong>Total Claimed</strong></li><li><strong>Approved amount</strong> (once HR has approved)</li><li><strong>Line items</strong> — each expense with its type, date, amount, and description</li></ul><h2 id="status-lifecycle" tabindex="-1">Status lifecycle <a class="header-anchor" href="#status-lifecycle" aria-label="Permalink to &quot;Status lifecycle&quot;">​</a></h2><p>A typical claim goes through:</p><ol><li><strong>Draft</strong> — you just submitted, not yet reviewed</li><li><strong>Pending</strong> — with an approver</li><li><strong>Approved</strong> — approver signed off; amount may be reduced vs claimed</li><li><strong>Paid</strong> — finance has settled the amount</li><li>(Or <strong>Rejected</strong> — with a reason; see your claim detail for notes)</li></ol><h2 id="common-issues" tabindex="-1">Common issues <a class="header-anchor" href="#common-issues" aria-label="Permalink to &quot;Common issues&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Message</th><th>Cause</th><th>Fix</th></tr></thead><tbody><tr><td>&quot;Every line needs a receipt photo&quot;</td><td>A line is missing a photo</td><td>Tap the empty photo slot to add one</td></tr><tr><td>Validation error on submit</td><td>Server rejected (e.g. missing Expense Claim Type config)</td><td>Contact HR — they may need to set up the claim type</td></tr><tr><td>Claim shows in &quot;Sync Errors&quot;</td><td>Submission failed on network issue</td><td>More → Sync Errors → Retry</td></tr></tbody></table><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/guide/payslip">View payslips</a></li><li><a href="/guide/offline">Working offline</a></li></ul>',32)])])}const g=t(s,[["render",l]]);export{m as __pageData,g as default};
